//-------------------------------------------------------------------------
// MRFProdStrServices::GetProductRefFromName()
//-------------------------------------------------------------------------
CATBaseUnknown * MRFProdStrServices::GetProductRefFromName(CATUnicodeString isReferenceName)
{
	CATBaseUnknown * pPLMNavBaseRef = NULL;
	CATIPLMProducts * pRDPLMProdOnRoot = GetRootPLMProduct();
	if (NULL != pRDPLMProdOnRoot)
	{
		CATIPrdIterator * pIterator = NULL;
		if (SUCCEEDED(pRDPLMProdOnRoot->Iterator(pIterator, IID_CATIPLMNavInstance)))
		{
			if (pIterator)
			{
				while (SUCCEEDED(pIterator->Next(pPLMNavBaseRef)) && (NULL != pPLMNavBaseRef))
				{
					CATIPLMNavInstance * piNavRepInstOnRepInst = NULL;
					HRESULT hr = pPLMNavBaseRef->QueryInterface(IID_CATIPLMNavInstance, (void**)&piNavRepInstOnRepInst);
					if (SUCCEEDED(hr))
					{
						CATIPLMNavReference *pNavRef = NULL;
						hr = piNavRepInstOnRepInst->GetReferenceInstanceOf(pNavRef);
						if (SUCCEEDED(hr) && (NULL != pNavRef))
						{
							CATUnicodeString iUAttrName = "V_Name";
							CATUnicodeString iUAttrValue = "";
							CATICkeObject_var spCkeObjectOnRef = pNavRef;
							CATCkeObjectAttrReadServices::GetValueAsString(spCkeObjectOnRef, iUAttrName, iUAttrValue);
							if (iUAttrValue == isReferenceName)
							{
								pPLMNavBaseRef = piNavRepInstOnRepInst;

								pNavRef->Release();
								pNavRef = NULL;
								break;
							}
						}
					}
				}
			}
			pIterator->Release(); pIterator = NULL;
		}
		pRDPLMProdOnRoot->Release();
		pRDPLMProdOnRoot=NULL;
	}
	return pPLMNavBaseRef;
}

//-------------------------------------------------------------------------
// MRFProdStrServices::GetRootNavReference()
//-------------------------------------------------------------------------
CATIPLMNavReference* MRFProdStrServices::GetRootNavReference()
{
	CATIPLMNavReference * pRefRoot = NULL;
	
	HRESULT hr = S_OK;
	CATFrmEditor * pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != pEditor)
	{
		CATListPtrCATIPLMComponent PLMRoot;
		CATPLMComponentInterfacesServices::GetEditedRootPLMComponents(pEditor, PLMRoot);

		if (0 < PLMRoot.Size())
		{
			CATIPLMComponent*  pPLMCompOnRoot = PLMRoot[1];
			if (NULL != pPLMCompOnRoot)
			{
				hr = pPLMCompOnRoot->QueryInterface(IID_CATIPLMNavReference, (void**)&pRefRoot);
				if (NULL != pRefRoot && SUCCEEDED(hr))
				{
					pPLMCompOnRoot->Release();
					pPLMCompOnRoot = NULL;
				}
			}
		}
	}
	//cout << "PLM Nav Ref in GetRootNavReference Success" << endl;
	return pRefRoot;
}

